#!/usr/bin/env python3
"""Generate the active W3.5 task queue with candidate re-execution first."""
from __future__ import annotations
from pathlib import Path
from report_link_utils import markdown_link
ROOT=Path(__file__).resolve().parents[1]
OUT=ROOT/'docs/planning/next-actions.md'; STATUS=ROOT/'docs/reports/project-status-generated.md'; GAP=ROOT/'docs/reports/research-gap-report.md'
TASKS=[
{"id":"STRATEGIC-003","priority":"high","title":"Execute evidence-complete candidate ablation and reconstruction","why":"The prior project-authored summaries were not atomic trial evidence and conflated primitive reducibility, genericity, scope dependence, and structural necessity. Execute 12 candidates across 18 frozen cases and source/GREL/FARA layers, preserving 648 atomic trial records, exact ablations, reconstructions, equivalence judgments, and machinery costs.","affected":["theory/evaluation/w3-5-candidate-test-contract-v1.0.json","theory/evaluation/w3-5-candidate-test-result-v1.0.json","theory/evaluation/universal-structure-candidate-registry.json","docs/research/w3-5-candidate-ablation-and-reconstruction-v1.0.md"],"outcome":"A generated multidimensional result separating primitive necessity, explicit representation necessity, structural commitment necessity, reasoning specificity, and architecture invariance. Genericity and derivability must not be aggregated as nonnecessity.","risk":"high","branch":"research/reexecute-w3-5-candidate-tests","pr":"Execute evidence-complete W3.5 candidate tests"},
{"id":"STRATEGIC-004","priority":"blocked","title":"Complete W3.5 machinery cost, claim-impact, and preserved-failure closure","why":"Cost and claim closure depend on the corrected candidate trial package and cannot treat preliminary observations as terminal evidence.","affected":["docs/research/w3-5-specificity-and-discovery-gate-v1.0.md","theory/evaluation/w3-5-specificity-and-discovery-gate.json","theory/evaluation/central-claim-registry.json","theory/evaluation/research-gates.json"],"outcome":"Complete closure artifacts only after candidate re-execution is evidence-complete.","risk":"high","branch":"research/close-w3-5-adjudication","pr":"Close W3.5 machinery, claim-impact, and failure audit"},
{"id":"STRATEGIC-005","priority":"blocked","title":"Assemble the finite-core theorem or strongest obstruction","why":"W5 remains blocked until candidate re-execution and every remaining W3.5 closure artifact are complete.","affected":["docs/research/s-core-construction-obstruction-ledger-v1.0.md","theory/evaluation/s-core-construction-obstruction-ledger.json","theory/evaluation/thm-target-001.json","theory/evaluation/central-claim-registry.json"],"outcome":"A bounded REP theorem or strongest explicit obstruction consistent with all corrected evidence.","risk":"high","branch":"research/assemble-s-core-result","pr":"Assemble S_core theorem or obstruction"}]
def nav_links(): return [f"- README Command Center: {markdown_link(ROOT/'README.md',OUT)}",f"- Project Status: {markdown_link(STATUS,OUT)}",f"- Research Gaps: {markdown_link(GAP,OUT)}",f"- Next Actions: {markdown_link(OUT,OUT)}"]
def main()->int:
    ids=[x['id'] for x in TASKS]; assert len(ids)==len(set(ids))
    lines=['# Next Actions','','## Navigation','',*nav_links(),'','Generated by `python tools/generate_next_tasks.py` under the separated REP, ADJ, and USD program.','','W0-W4 remain complete bounded REP packages. Corpus freeze, bounded factorization, registered discrimination, and qualified FARA-specificity remain complete. Candidate testing is not complete: the prior summaries are preserved only as preliminary internal observations, while structural indispensability remains unresolved and 648 atomic trials require execution. W5 remains blocked.','','## Ranked Next Actions','']
    for task in TASKS:
        affected=[markdown_link(ROOT/path,OUT) for path in task['affected']]
        lines += [f"### {task['id']}: {task['title']}",'','- Source: central research program',f"- Priority: {task['priority']}",f"- Why it matters: {task['why']}",'- Affected files:',*[f'  - {item}' for item in affected],f"- Expected outcome: {task['outcome']}",f"- Risk level: {task['risk']}",f"- Suggested branch name: `{task['branch']}`",f"- Suggested PR title: `{task['pr']}`",'']
    lines += ['## Maintainer Task Briefs','','Preserve all completed bounded results and nonclaims. Candidate re-execution must derive results from atomic records rather than hard-coded answers, distinguish primitive reducibility from structural necessity, count equivalent reintroduction correctly, and include reconstruction machinery cost. Do not begin W5 while `W3.5-SDG-001` remains unresolved.','','Validation commands:','','- `make research-check`','- `make health-fast`','','## Navigation','',*nav_links()]
    OUT.write_text('\n'.join(lines)+'\n',encoding='utf-8'); print(f"{OUT.relative_to(ROOT)} tasks={len(TASKS)}"); return 0
if __name__=='__main__': raise SystemExit(main())
